13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type Damage = { itemType: string; amount: number };
17	type Incident = { cause: string; damages: Damage[] };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	type Step = QuoteStep | ClaimStep;
21	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
22	
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	
25	const claimStep = (step: ClaimStep): { payout: number } => {
26	  const payout = step.incident.damages.reduce(
27	    (sum, d) => sum + (d.amount - DEDUCTIBLE_PER_DAMAGE),
28	    0,
29	  );
30	  return { payout };
31	};
32	
33	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
34	
35	const BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PRICE = 60;
37	
38	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
39	
40	const sumItemBasePremiums = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const group = groups.get(item.type) ?? [];
47	    group.push(item);
48	    groups.set(item.type, group);
49	  }
50	  return groups;
51	};
52	
53	const priceComponentGroup = (group: Item[]): number =>
54	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
55	
56	const computeBasePremium = (items: Item[]): number => {
57	  const components = items.filter(isComponent);
58	  const nonComponents = items.filter((item) => !isComponent(item));
59	  const componentGroups = [...groupByType(components).values()];
60	  const componentTotal = componentGroups.reduce(
61	    (sum, group) => sum + priceComponentGroup(group),
62	    0,
63	  );
64	  return sumItemBasePremiums(nonComponents) + componentTotal;
65	};
66	
67	const CURSE_SURCHARGE_RATE = 0.5;
68	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
69	const HIGH_ENCHANTMENT_THRESHOLD = 5;
70	
71	const itemSurcharge = (item: Item): number => {
72	  const base = itemBasePremium(item);
73	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
74	  const enchantment =
75	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
76	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
77	      : 0;
78	  return curse + enchantment;
79	};
80	
81	const sumItemSurcharges = (items: Item[]): number =>
82	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
83	
84	const LOYALTY_DISCOUNT_RATE = 0.2;
85	const LOYALTY_THRESHOLD_YEARS = 2;
86	
87	type Customer = { yearsWithMHPCO: number };
88	type PolicyContext = { customer: Customer; contractIndex: number };
89	
90	const loyaltyDiscount = (base: number, customer: Customer): number =>
91	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
92	
93	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
94	
95	const followUpDiscount = (base: number, contractIndex: number): number =>
96	  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
97	
98	const sumPolicyDiscounts = (base: number, ctx: PolicyContext): number =>
99	  loyaltyDiscount(base, ctx.customer) + followUpDiscount(base, ctx.contractIndex);
100	
101	const sumPolicySurcharges = (base: number): number => base * FIRST_INSURANCE_RATE;
102	
103	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
104	  const base = computeBasePremium(step.items);
105	  const surcharges = sumItemSurcharges(step.items) + sumPolicySurcharges(base);
106	  const discounts = sumPolicyDiscounts(base, ctx);
107	  return {
108	    premium: Math.ceil(base + surcharges - discounts + PROCESSING_FEE),
109	  };
110	};
111	
112	export const runScenario = (scenario: unknown): unknown => {
113	  const { customer, steps } = scenario as Scenario;
114	  let contractIndex = 0;
115	  const results = steps.map((step) => {
116	    if (step.op === "claim") {
117	      return claimStep(step);
118	    }
119	    const result = quoteStep(step, { customer, contractIndex });
120	    contractIndex += 1;
121	    return result;
122	  });
123	  return { results };
124	};
